// Parse target URLs from form input
const formData = $input.first().json;
const urlsText = (formData.target_urls || '').trim();
const scanLabel = (formData.scan_label || '').trim();
const focusAreas = (formData.focus_areas || '').trim();

function normalizeUrl(raw) {
  if (!raw) return '';
  let u = raw.trim().replace(/[),.;]+$/, '');
  if (!/^https?:\/\//i.test(u)) u = 'https://' + u;
  const hostish = u.replace(/^https?:\/\//i, '');
  if (!hostish.includes('.')) return '';
  return u;
}

const lines = urlsText.split(/\r?\n/).map(s => s.trim()).filter(Boolean);

const targets = lines.map((line, index) => {
  const url = normalizeUrl(line);
  let domain = '';
  try { domain = new URL(url).hostname.replace(/^www\./, ''); } catch (e) { domain = line; }
  return {
    id: `target-${index + 1}`,
    url,
    domain,
    scan_label: scanLabel,
    focus_areas: focusAreas
  };
}).filter(t => t.url);

return targets.map(t => ({ json: t }));

// Build a numbered URL list for LLM goal planning
const items = $input.all();
let urlList = '';
let scanLabel = '';
let focusAreas = '';

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  if (i === 0) {
    scanLabel = item.scan_label || '';
    focusAreas = item.focus_areas || '';
  }
  urlList += `${i + 1}. ${item.domain} (${item.url})`;
  if (i < items.length - 1) urlList += '\n';
}

return { json: { urlList, scanLabel, focusAreas } };

