// Parse OpenAI response and flatten into one item per (domain, phase)
const j = $input.first().json;

const text =
  j?.output?.[0]?.content?.find(c => c?.type === 'output_text')?.text
  ?? j?.output?.[0]?.content?.[0]?.text
  ?? null;

if (!text) {
  return [{ json: { error: 'No output_text in planning response', raw: j } }];
}

let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  const stripped = text.replace(/```json\s*|```/g, '').trim();
  parsed = JSON.parse(stripped);
}

const plans = Array.isArray(parsed?.scan_plans) ? parsed.scan_plans : [];

// Flatten: one item per (domain, phase)
const items = [];
for (const plan of plans) {
  for (const goal of (plan.goals || [])) {
    items.push({
      domain: plan.domain || '',
      url: plan.url || '',
      phase: goal.phase,
      phase_name: goal.phase_name || '',
      goal: goal.goal || ''
    });
  }
}

return items.map(i => ({ json: i }));

// Prepare TinyFish run parameters for each (domain, phase) pair
const item = $input.item.json;

let runUrl = item.url || '';
if (runUrl && !runUrl.startsWith('http://') && !runUrl.startsWith('https://')) {
  runUrl = 'https://' + runUrl;
}

const phaseNames = {
  1: 'Bundle Intelligence',
  2: 'Page-visible Resources',
  3: 'Infrastructure Signals',
  4: 'Runtime Config',
  5: 'Security Signals'
};

const phase = item.phase || 1;
const phaseName = item.phase_name || phaseNames[phase] || `Phase ${phase}`;

let runGoal = item.goal || '';
if (!runGoal) {
  runGoal = `Load ${runUrl} fully, scroll the page to trigger lazy-loaded scripts, then extract all observable ${phaseName} signals from the DOM, script tags, link tags, global variables, and page source. Do not use DevTools or the Network tab. Return findings as structured JSON.`;
}

runGoal += '\n\nReturn your findings as structured JSON with clearly labelled keys. Include a sources array of any relevant URLs or script paths where you found evidence.';

return {
  json: {
    id: item.id,
    domain: item.domain,
    url: runUrl,
    phase,
    phase_name: phaseName,
    scan_label: item.scan_label,
    focus_areas: item.focus_areas,
    runUrl,
    runGoal
  }
};

// Evaluate Runs — aggregate across ALL incoming items
const items = $input.all().map(i => i.json);

let runs = [];
for (const x of items) {
  if (Array.isArray(x)) runs.push(...x);
  else if (Array.isArray(x?.data)) runs.push(...x.data);
  else if (Array.isArray(x?.runs)) runs.push(...x.runs);
  else if (x && (x.run_id || x.status)) runs.push(x);
}

const seen = new Set();
runs = runs.filter(r => {
  const id = r?.run_id ?? r?.runId ?? JSON.stringify(r);
  if (seen.has(id)) return false;
  seen.add(id);
  return true;
});

const terminal = new Set(['COMPLETED', 'FAILED', 'CANCELLED']);
const allDone =
  runs.length > 0 &&
  runs.every(r => terminal.has(String(r.status || '').toUpperCase()));

return [{ json: { raw: items, runs, allDone } }];

// Rehydrate per-run items for next poll
const inItem = $input.first().json;
const arr = Array.isArray(inItem.runs)
  ? inItem.runs
  : (Array.isArray(inItem.raw) ? inItem.raw : []);
const runIds = arr.map(r => r?.run_id || r?.runId).filter(Boolean);
return runIds.map(runId => ({ json: { runId, run_id: runId } }));

// Normalize TinyFish runs and merge with target context
const targetItems = $("Match URLs with Goals")?.all?.() ?? [];
const targets = targetItems.map(it => {
  const j = it.json ?? {};
  return {
    id: j.id ?? null,
    domain: j.domain ?? '',
    url: j.url ?? '',
    phase: j.phase ?? null,
    phase_name: j.phase_name ?? '',
    scan_label: j.scan_label ?? '',
    focus_areas: j.focus_areas ?? '',
    runUrl: j.runUrl ?? j.url ?? '',
    runGoal: j.runGoal ?? j.goal ?? ''
  };
}).filter(t => t.url);

// Group targets by domain for later grouping
const domainMap = {};
for (const t of targets) {
  if (!domainMap[t.domain]) domainMap[t.domain] = { domain: t.domain, url: t.url, scan_label: t.scan_label, focus_areas: t.focus_areas, phases: [] };
  domainMap[t.domain].phases.push({ phase: t.phase, phase_name: t.phase_name });
}

const inItems = $input.all().map(i => i.json);
let runsRaw = [];
for (const x of inItems) {
  if (Array.isArray(x)) runsRaw.push(...x);
  else if (Array.isArray(x?.data)) runsRaw.push(...x.data);
  else if (Array.isArray(x?.runs)) runsRaw.push(...x.runs);
  else if (x?.run_id || x?.status) runsRaw.push(x);
}

const runs = runsRaw.map(run => {
  const status = String(run.status ?? '').toUpperCase();
  const resultObj = run.result ?? null;
  return {
    run_id: run.run_id ?? null,
    status,
    goal: run.goal ?? '',
    created_at: run.created_at ?? null,
    finished_at: run.finished_at ?? null,
    error: run.error ?? null,
    result: resultObj,
    rawResultText: resultObj ? JSON.stringify(resultObj, null, 2) : ''
  };
});

return [{
  json: {
    targets: Object.values(domainMap),
    allTargets: targets,
    runs,
    allDone: runs.length > 0 && runs.every(r => ['COMPLETED', 'FAILED', 'CANCELLED'].includes(r.status))
  }
}];

// Build full extraction payload grouped by domain for LLM synthesis
const root = $input.first().json;
const targets = Array.isArray(root.targets) ? root.targets : [];
const allTargets = Array.isArray(root.allTargets) ? root.allTargets : [];
const runs = Array.isArray(root.runs) ? root.runs : [];

// Group runs by domain using goal text heuristic
const byDomain = {};
for (const t of targets) {
  byDomain[t.domain] = {
    domain: t.domain,
    url: t.url,
    scan_label: t.scan_label,
    focus_areas: t.focus_areas,
    phases: t.phases || [],
    runs: runs.filter(r => (r.goal || '').toLowerCase().includes(t.domain.toLowerCase()) || (r.goal || '').includes(t.url))
  };
}

// If no domain-matched runs, attach all runs to each domain (fallback)
for (const d of Object.values(byDomain)) {
  if (d.runs.length === 0) d.runs = runs;
}

const payload = {
  scanLabel: targets[0]?.scan_label || '',
  targetCount: targets.length,
  runCount: runs.length,
  byDomain,
  allRuns: runs
};

return [{
  json: {
    targets,
    runs,
    byDomain,
    scanLabel: payload.scanLabel,
    researchPayloadText: JSON.stringify(payload, null, 2)
  }
}];

