// Extract and parse the structured stack report from OpenAI output
const j = $input.first().json;

const text =
  j?.output?.[0]?.content?.find(c => c?.type === 'output_text')?.text
  ?? j?.output?.[0]?.content?.[0]?.text
  ?? null;

if (!text) {
  return [{ json: { error: 'No output_text in synthesis response', raw: j } }];
}

let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  const stripped = text.replace(/```json\s*|```/g, '').trim();
  try {
    parsed = JSON.parse(stripped);
  } catch (e2) {
    return [{ json: { error: 'Failed to parse synthesis JSON', rawText: text } }];
  }
}

return [{ json: { stackReport: parsed, rawText: text } }];

// Combine run metadata with stack report
const items = $input.all().map(i => i.json);
const runData = items.find(x => Array.isArray(x.runs) || Array.isArray(x.targets)) || {};
const reportData = items.find(x => x.stackReport) || {};

return [{
  json: {
    ...runData,
    stackReport: reportData.stackReport || {},
    generatedAt: new Date().toISOString()
  }
}];

// Build Markdown report content for each domain
const j = $json;
const domains = j.domains_scanned || '';
const scanLabel = j.scan_label || 'BundleRadar Scan';
const createdAt = j.scanned_at || new Date().toISOString();

let fullReport = {};
try { fullReport = JSON.parse(j.full_report_json || '{}'); } catch (e) {}

const reports = Array.isArray(fullReport.reports) ? fullReport.reports : [];

const domainSections = reports.map(r => {
  const stack = r.tech_stack || {};
  const sec = r.security_posture || {};
  const insights = Array.isArray(r.competitive_insights) ? r.competitive_insights : [];
  const warnings = Array.isArray(r.warnings) ? r.warnings : [];
  const failed = Array.isArray(r.failed_phases) ? r.failed_phases : [];

  const listOrDash = (arr) => Array.isArray(arr) && arr.length
    ? arr.map(x => typeof x === 'string' ? x : `${x.name || ''}${x.version ? ' ' + x.version : ''} [${x.confidence || '?'}]`).join(', ')
    : '—';

  const single = (obj) => obj && obj.name
    ? `${obj.name}${obj.version ? ' ' + obj.version : ''} [${obj.confidence || '?'}]`
    : '—';

  const bool = (v) => v === true ? 'Yes' : v === false ? 'No' : 'Unknown';

  return [
    `## ${r.domain || 'Unknown'}`,
    ``,
    `### Tech Stack`,
    `| Category | Detected |`,
    `|---|---|`,
    `| Framework | ${single(stack.framework)} |`,
    `| UI Library | ${listOrDash(stack.ui_library)} |`,
    `| Build Tool | ${single(stack.build_tool)} |`,
    `| State Management | ${listOrDash(stack.state_management)} |`,
    `| Analytics | ${listOrDash(stack.analytics)} |`,
    `| Monitoring | ${listOrDash(stack.monitoring)} |`,
    `| Feature Flags | ${listOrDash(stack.feature_flags)} |`,
    `| Auth | ${listOrDash(stack.auth)} |`,
    `| Payments | ${listOrDash(stack.payments)} |`,
    `| CDN / Hosting | ${single(stack.cdn_hosting)} |`,
    `| CMS | ${listOrDash(stack.cms)} |`,
    `| Third-party Tools | ${listOrDash(stack.third_party_tools)} |`,
    ``,
    `### Security Posture`,
    `- CSP Present: ${bool(sec.csp_present)}`,
    `- HSTS Present: ${bool(sec.hsts_present)}`,
    `- Source Maps Exposed: ${bool(sec.source_maps_exposed)}`,
    `- Leaked Secrets: ${bool(sec.leaked_secrets)}`,
    sec.notes ? `- Notes: ${sec.notes}` : '',
    ``,
    `### Architecture Summary`,
    r.architecture_summary || '_No summary available._',
    ``,
    `### Architecture Diagram`,
    '```',
    r.architecture_ascii || '_No diagram available._',
    '```',
    ``,
    `### Competitive Insights`,
    insights.length ? insights.map((ins, i) => `${i + 1}. ${ins}`).join('\n') : '_No insights available._',
    ``,
    failed.length ? `### Failed Phases\nPhases with no data: ${failed.join(', ')}` : '',
    warnings.length ? `### Warnings\n${warnings.map(w => `- ${w}`).join('\n')}` : '',
    ``
  ].filter(line => line !== undefined).join('\n');
}).join('\n---\n\n');

const safe = (scanLabel || domains || 'scan')
  .replace(/[^a-z0-9-_ ,]/gi, '').slice(0, 60).trim().replace(/[\s,]+/g, '-');
const mdFilename = `bundleradar-report-${safe}-${Date.now()}.md`;

const mdContent =
`# BundleRadar — Frontend Tech Stack Report

**Scan Label:** ${scanLabel}
**Domains:** ${domains}
**Generated:** ${createdAt}

---

${domainSections || '_No report data available._'}
`;

return [{ json: { mdFilename, mdContent } }];

const baseName = ($json.mdFilename || `bundleradar-report-${Date.now()}`).trim();
const filename = baseName.toLowerCase().endsWith('.md') ? baseName : `${baseName}.md`;
const md = $json.mdContent || '';

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(md, 'utf8'),
  filename,
  'text/markdown'
);

return [{ json: { mdFilename: filename }, binary: { data: binaryData } }];

const data = $json;
const content = JSON.stringify(data, null, 2);
const filename = `bundleradar-scan-${Date.now()}.json`;

return [{
  json: data,
  binary: {
    data: await this.helpers.prepareBinaryData(
      Buffer.from(content, 'utf8'),
      filename,
      'application/json'
    )
  }
}];
